#include <bits/stdc++.h>
using namespace std;
const int maxn=5e5;
int n,m,vis[maxn];
vector<int> e[maxn];
void dfs(int s,int x){
	if(!vis[x]){
		vis[x]=s;
		for(int i:e[x]){
			dfs(s,i);
		}
	}
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,x,y;i<=m;i++){
		cin>>x>>y;
		e[y].push_back(x);
	}
	for(int i=n;i>=1;i--){
		dfs(i,i);
	}
	for(int i=1;i<=n;i++){
		cout<<vis[i]<<" ";
	}
	return 0;
}
